async (params, browser) => {
  // Open recent papers
  await browser.open(`https://arxiv.org/list/${params.category}/recent`)

  // Wait for list
  await browser.waitForSelector('#dlpage, .list-title', 15000)

  // Let page render
  await browser.wait(2000)

  // Extract recent papers
  const results = await browser.evaluate(`const papers = []; document.querySelectorAll('dt').forEach((dt, i) => { if (i < 20) { const idEl = dt.querySelector('a[href*="/abs/"]'); const dd = dt.nextElementSibling; const titleEl = dd?.querySelector('.list-title'); const authorsEl = dd?.querySelector('.list-authors'); papers.push({ arxiv_id: idEl?.textContent?.trim() || '', url: idEl?.href || '', title: titleEl?.textContent?.replace('Title:', '')?.trim() || '', authors: authorsEl?.textContent?.replace('Authors:', '')?.trim()?.slice(0, 200) || '' }); } }); return { category: '' + params.category + '', paper_count: papers.length, papers };`)

  return results
}
